export function getDescendantItems(category: Category): QuizItem[] {
  return [
    ...category.items,
    ...category.children.flatMap((child) => getDescendantItems(child)),
  ];
}

export function getAllItems(): QuizItem[] {
  return categories.flatMap((category) => getDescendantItems(category));
}

export function getCategoryById(id: string): Category | undefined {
  const stack = [...categories];
  while (stack.length) {
    const current = stack.shift()!;
    if (current.id === id) return current;
    stack.push(...current.children);
  }
  return undefined;
}

export function getParentCategory(id: string): Category | undefined {
  const stack = [...categories];
  while (stack.length) {
    const current = stack.shift()!;
    if (current.children.some((child) => child.id === id)) return current;
    stack.push(...current.children);
  }
  return undefined;
}

export function getItemById(id: string): QuizItem | undefined {
  return getAllItems().find((item) => item.id === id);
}

export function getTotalItemCount(): number {
  return getAllItems().length;
}
